#Para realizar la operacion O(n) una sola vez
GENEROS_COMUN_SET = set(GENEROS_COMUN)

def mapeo_nivel_ansiedad(row):
  genero_encuestado = row['Fav genre']
  ansiedad_encuestado = row['Anxiety']
  if genero_encuestado not in GENEROS_COMUN_SET : return []
  if ansiedad_encuestado >= 7:
    return [(genero_encuestado,'Alto')]
  return [(genero_encuestado,'Bajo')]

rdd_genero_ansiedad = rdd_mxsm.flatMap(mapeo_nivel_ansiedad).cache()

#Me interesa saber la distribucion entre alto y bajo
rdd_genero_ansiedad.map(lambda x: (x[1],1)).reduceByKey(lambda x,y: x+y).collect()

"""Hay una distribucion bastante uniforme.

"""

#Ahora hago algo similar con la tabla de canciones, quedandome unicamente con
#los generos que me interesan. El formato sera (genero,accust) y luego me interesa
#quedarme con el promedio de este para cada genero.

#Ademas agrego un 1 para luego poder hacer el promedio

def mapeo_accousticness(row):
  genero = row['genre']
  accoust = row['acousticness']
  if genero not in GENEROS_COMUN_SET : return []
  return [(genero,(accoust,1))]

rdd_prom_accoust = rdd_canciones.flatMap(mapeo_accousticness)\
                          .reduceByKey(lambda x,y: (x[0]+y[0],x[1]+y[1]))\
                          .map(lambda x: (x[0],(x[1][0]/x[1][1])*100))

#me quedo con algo del estilo (genero,(cant_altas,cant_bajas))

def sumar_segun_nivel_ansiedad(x):
  # (genero,(alto,bajo))
  if x[1] == 'Alto': return (x[0],(1,0))
  return (x[0],(0,1))



rdd_genero_cantidad_nivel =rdd_genero_ansiedad.map(sumar_segun_nivel_ansiedad)\
                  .reduceByKey(lambda x,y: (x[0]+y[0],x[1]+y[1]))

#Ahora hago el join para ver los niveles de cada uno
# nos va a quedar el formato (genero, (cant_alto,cant_bajo),nivel_accout)
rdd_genero_cantidad_nivel.join(rdd_prom_accoust).collect()

"""**Conclusión:** el genero con mayor acousticness es el _Jazz_ y tiene igual cantidad de personas en alto que en bajo, algo similar sucede con country.

El resto de los generos podemos notar que no tienen niveles muy altos de este estilo musical, en especial el caso de Rock, en el que contamos con 106 encuestados con nivel alto de ansiedad y tan solo un 20% aprox de nivel de musica acustica.

Como podemos notar no solo no hay un patron claro entre acousticness y los encuestados con altos niveles de ansiedad, sino que la cantidad de _Altos_ y _Bajos_ por cada genero es muy similar. Por lo tanto se refuta la hipotesis, la ansiedad no se asocia al perfir acustico del genero favorito del encuestado.

## Relación entre escuchar música en idioma extranjero y exploración musical

La pregunta es: ¿Existe relacion entre escuchar musica en un idioma extranjero y tener mayor predisposicion a explorar generos nuevos?

**Hipótesis**: Se asume que una persona la cual esta dispuesta a escuchar música en un idioma que no es el suyo tambien tiene una actitud mas _abierta_ hacia cosas distintas, lo que refleja tambien una mayor exploracion musical.
"""

#La idea es dividir a la gente entre los que escuchan y los que no escuchan
#musica extranjera y ver los porcentajes de exploracion de ambas.

#Me quedo con los (m_extran,(si_explora,1)) por cada encuestado
def map_idioma_exploracion(row):
  grupo = 'Escucha extranjera' if row['Foreign languages'] else 'No escucha extranjera'
  #Le pongo 1 si explora y 0 si no
  explora= 1 if row['Exploratory'] else 0
  return (grupo,(explora,1))#el 1 es para luego sumar

#genero un registro por cada encuestado
rdd_idioma_expl = rdd_mxsm.map(map_idioma_exploracion)

#sumo la cantidad de gente que explora y ademas me quedo con el total por grupo para
#tener la proporcion
#me queda : (extranjera/no, (cant_exploran,cant_total))

#seguido a eso calculo el porcentaje (luego del \)

rdd_idioma_expl.reduceByKey(lambda x,y: (x[0]+y[0],x[1]+y[1]))\
               .map( lambda x: (x[0],(x[1][0]/x[1][1])*100)).collect()

"""De los que escuchan musica extranjera casi un 80% de ellos tambien explora musica nueva, mientras que los que no lo hacen solo en un 62% tienden a explorar nuevos generos.

**Conclusión:** Por lo tanto podemos confirmar la hipotesis planteada. Esto porque el grupo de encuestados que consume muúica en un idioma distinto al _propio_ tienen un porcentaje de exploracion musical mayor al otro grupo. Aunque los que no escuchan musica extranjera tambien tienen un porcentaje alto.

## Relacion entre el tempo (BPM) y el nivel promedio de ansiedad

La pregunta es: ¿Los encuestados que escuchan musica mucho mas acelerada/intensa(con BPM alto) presentan en promedio mayores niveles de ansiedad?

**Hipotesis:** Se asume que la musica mas rapida (BPM alto) podria estar relacionada con mayores niveles de ansiedad en el encuestado, mientras que los ritmos mas bajos (BPM menor, tomare los menores a 100) harian que tenga un menor nivel de ansiedad.

Se propone la siguiente categorizacion los BPM promedio por encuentado:
- Lento : <100 BPM
- Moderado : 100 - 130 BPM
- Rapido : >130 BPM

Consulta previa a optimizar:

despues me di cuenta que hacer un filter y luego un map se podia simplificar a utilizar de una un flatMap como ya lo hice previamente.
```
#En primer lugar y como se vio en el analisis exploratorio hay algunos valores
#de BPM los cuales eran desconocidos y no es algo que se pueda inferir de manera
# precisa, por lo que para esta consulta filtrare a esos valores nulos
rdd_bpm = rdd_mxsm.filter(lambda row: row['BPM']is not None)

def mapeo_bpm_ansiedad(row):
  bpm = row['BPM']
  nivel_ansiedad = row['Anxiety']

  #realizo el mapeo segun el tempo
  if bpm < 100:
    categoria = 'Lento'
  elif 100 <= bpm <= 130:
    categoria = 'Moderado'
  else:
    categoria = 'Rapido'

  return (categoria,(nivel_ansiedad,1))

#genero un registro por cada encuestado (categoria,(nivel_ansiedad,1))
#luego con el reduceByKey sumo tanto el nivel de ansiedad como el 1
#para asi poder realizar el promedio
rdd_categorias = rdd_bpm.map(mapeo_bpm_ansiedad).reduceByKey(lambda x,y: (x[0]+y[0],x[1]+y[1]))

#ahora me quedo con el promedio de cada una de las categorias de los tempos
rdd_categorias.map(lambda x: (x[0],x[1][0]/x[1][1])).collect()
```
"""

#Filtro los nulos y al mismo tiempo mapeo segun el BPM utilizando un flatMap
#genero un registro por cada encuestado (categoria,(nivel_ansiedad,1))

def mapeo_bpm_ansiedad(row):
  bpm = row['BPM']
  if bpm is None : return []

  nivel_ansiedad = row['Anxiety']

  #realizo el mapeo segun el tempo
  if bpm < 100:
    categoria = 'Lento'
  elif 100 <= bpm <= 130:
    categoria = 'Moderado'
  else:
    categoria = 'Rapido'

  return [(categoria,(nivel_ansiedad,1))]

#luego con el reduceByKey sumo tanto el nivel de ansiedad como el 1
#para asi poder realizar el promedio
rdd_mxsm.flatMap(mapeo_bpm_ansiedad)\
        .reduceByKey(lambda x,y: (x[0]+y[0],x[1]+y[1]))\
        .map(lambda x: (x[0],x[1][0]/x[1][1])).collect()
        #con este ultimo map me quedo con el promedio de cada una de las categorias de los tempos

